# What p99 latency does production actually see? (over last 30 days)
histogram_quantile(0.99,
  sum by (le)(
    increase(claude_api_request_duration_seconds_bucket[30d])
  )
)

# What was the p99.9 during incidents? (filter to error periods)
histogram_quantile(0.999,
  sum by (le)(
    rate(claude_api_request_duration_seconds_bucket[1h])
  )
)

# Silence all Claude alerts for 30 minutes during deployment
# (use the Alertmanager API or the UI)
curl -sS --fail -X POST "$ALERTMANAGER_URL/api/v2/silences" \
  -H "Content-Type: application/json" \
  -d '{
    "matchers": [
      {"name": "job", "value": "claude-api-proxy", "isRegex": false}
    ],
    "startsAt": "'$(date -u +%Y-%m-%dT%H:%M:%SZ)'",
    "endsAt": "'$(date -u -d "+30 minutes" +%Y-%m-%dT%H:%M:%SZ)'",
    "comment": "Deploying claude-api-proxy v2.3.1",
    "createdBy": "deploy-pipeline"
  }'
